(()=>{'use strict';
const $=s=>document.querySelector(s),T=v=>String(v??'').trim(),N=v=>Number(String(v??'').replace(/,/g,''))||0;
const F=n=>N(n).toLocaleString('th-TH'),B=n=>N(n).toLocaleString('th-TH',{minimumFractionDigits:2,maximumFractionDigits:2});
const sort=new Intl.Collator('th-u-kn-true',{numeric:true,sensitivity:'base'});let rows=[],meta={},payload=null;
function esc(s){return T(s).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}
function norm(s){return T(s).toLowerCase().replace(/[\s_\-./()[\]:]+/g,'')}
function realTele(r){const tele=T(r.tele),ps=T(r.ps),a=norm(tele),b=norm(ps);return !!tele && !(a&&b&&(a===b||a.includes(b)||b.includes(a)))}
function f(){return{start:T($('#startDate')?.value),end:T($('#endDate')?.value),ps:T($('#psSelect')?.value),receiver:T($('#storeSelect')?.value),brand:T($('#brandSelect')?.value),type:T($('#typeSelect')?.value),q:T($('#q')?.value).toLowerCase()}}
function appKey(){return meta.id||payload?.version_id||meta.file_name||''}
function state(){try{return JSON.parse(localStorage.getItem('doit-json:'+appKey())||'{}')}catch{return{}}}
function saveState(s){localStorage.setItem('doit-json:'+appKey(),JSON.stringify(s||{}))}
function hist(){try{return JSON.parse(localStorage.getItem('doit-print-history-v1:'+appKey())||'[]')}catch{return[]}}
function saveHist(h){localStorage.setItem('doit-print-history-v1:'+appKey(),JSON.stringify(h||[]))}
function pk(r){return[r.brand,r.size,r.code||r.sku,r.sku,r.type].join('|')}
function pkFromKey(k){return String(k).split('|').slice(4).join('|')}
function recFromKey(k){return String(k).split('|')[3]||''}
function scopeHead(){return window.DOIT_SCOPE_HEAD?.()||[T($('#startDate')?.value),T($('#endDate')?.value),T($('#psSelect')?.value)].join('|')+'|'}
function base(visible=true){const x=f();return rows.filter(r=>!realTele(r)&&(!x.start||r.date>=x.start)&&(!x.end||r.date<=x.end)&&(!x.ps||r.ps===x.ps)&&(!visible||!x.brand||r.brand===x.brand)&&(!visible||!x.type||r.type===x.type)&&(!visible||!x.q||[r.date,r.inv,r.code,r.sku,r.store,r.ps,r.brand,r.size,r.type].join(' ').toLowerCase().includes(x.q)))}
function group(visible=true){const m=new Map();base(visible).forEach(r=>{const k=pk(r);let g=m.get(k);if(!g){g={poolKey:k,brand:r.brand,size:r.size,code:r.code,sku:r.sku,type:r.type,qty:0,amt:0,unit:r.unit||0};m.set(k,g)}g.qty+=N(r.qty);g.amt+=N(r.amt);g.unit=g.qty&&g.amt?g.amt/g.qty:g.unit});return[...m.values()].sort((a,b)=>sort.compare(a.brand,b.brand)||sort.compare(a.size,b.size)||sort.compare(a.code||'',b.code||'')||sort.compare(a.sku,b.sku))}
function deliveryLines(){const st=state(),send=st.send||{},gm=new Map(group(false).map(g=>[g.poolKey,g])),out=[];Object.keys(send).filter(k=>k.startsWith(scopeHead())).forEach(k=>{const q=N(send[k]);if(q<=0)return;const g=gm.get(pkFromKey(k)),store=recFromKey(k);if(g&&store)out.push({store,code:g.code||'',name:g.sku,brand:g.brand,size:g.size,type:g.type,qty:q,unit:g.unit||0})});return out.sort((a,b)=>sort.compare(a.store,b.store)||sort.compare(a.brand,b.brand)||sort.compare(a.name,b.name))}
function csv(e){e?.preventDefault?.();e?.stopImmediatePropagation?.();const out=[['ชื่อรายการ','จำนวน']];group(true).forEach(g=>out.push([g.sku,g.qty]));const blob='\ufeff'+out.map(a=>a.map(x=>'"'+String(x??'').replace(/"/g,'""')+'"').join(',')).join('\n');const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([blob],{type:'text/csv;charset=utf-8'}));a.download='doit-pick-list-name-qty.csv';a.click()}
function css(){if($('#doitPrintCss308'))return;const s=document.createElement('style');s.id='doitPrintCss308';s.textContent='body.printMode>*:not(#doitPrintOverlay){display:none!important}#doitPrintOverlay{position:fixed;inset:0;z-index:9999;background:#fff;color:#000;overflow:auto}#doitPrintOverlay .bar{position:sticky;top:0;background:#fff;border-bottom:1px solid #000;padding:8px;display:flex;justify-content:space-between;gap:8px}#doitPrintOverlay .bar button{border:1px solid #000;background:#fff;color:#000;font-weight:900;border-radius:4px;padding:7px 10px}#doitPrintOverlay .bar button:disabled{opacity:.45}#doitPrintOverlay .page{background:#fff;color:#000;width:194mm;min-height:281mm;margin:8px auto;padding:7mm;page-break-after:always}#doitPrintOverlay .head{display:flex;justify-content:space-between;border-bottom:1px solid #000;margin-bottom:6px;padding-bottom:5px}#doitPrintOverlay .shop{font-size:16px;font-weight:900}#doitPrintOverlay table{width:100%;border-collapse:collapse;font-size:12px}#doitPrintOverlay th,#doitPrintOverlay td{border:.5pt solid #000;padding:3px 4px;background:#fff!important;color:#000!important}#doitPrintOverlay .r{text-align:right}#doitPrintOverlay .price{width:70px;text-align:right;border:0;background:#fff;color:#000;font:inherit}#doitPrintOverlay .sign{display:grid;grid-template-columns:1fr 1fr 1fr;gap:16px;margin-top:22px;text-align:center}#doitPrintOverlay .sign div{border-top:.5pt solid #000;padding-top:6px}@media print{@page{size:A4;margin:8mm}#doitPrintOverlay{position:static!important;overflow:visible!important}.bar{display:none!important}#doitPrintOverlay .page{width:auto!important;min-height:auto!important;margin:0!important;padding:0!important}#doitPrintOverlay table{font-size:11px!important}#doitPrintOverlay th,#doitPrintOverlay td{border:.5pt solid #000!important;padding:2.5px 3px!important}.price{border:0!important}}';document.head.appendChild(s)}
function closePrint(){document.body.classList.remove('printMode');$('#doitPrintOverlay')?.remove()}
function recalc(root=document){root.querySelectorAll('.page').forEach(pg=>{let sum=0;pg.querySelectorAll('.price').forEach(inp=>{const v=N(inp.value)*N(inp.dataset.qty);sum+=v;inp.closest('tr').querySelector('.total').textContent=B(v)});pg.querySelector('.billTotal').textContent=B(sum)})}
function printNow(){recalc(document);window.focus?.();window.print()}
function updateConfirmBtn(){const rec=T($('#storeSelect')?.value),b=$('#doitConfirmPrint');if(!b)return;b.textContent=rec?'✓ ปิดบิล: '+rec:'เลือกร้านก่อนปิดบิล';b.disabled=!rec}
function buildPrint(e){e?.preventDefault?.();e?.stopImmediatePropagation?.();css();$('#doitPrintOverlay')?.remove();const data=deliveryLines();if(!data.length){alert('ยังไม่ได้ใส่จำนวนส่งจริงให้ร้านใด');return}const by={};data.forEach(l=>(by[l.store]??=[]).push(l));const ov=document.createElement('div');ov.id='doitPrintOverlay';ov.innerHTML='<div class="bar"><b>โหมดปริ้นประหยัดหมึก: เส้นดำพื้นขาว</b><span><button id="doitClosePrint" type="button">ปิด</button> <button id="doitConfirmPrint" type="button"></button> <button id="doitPrintNow" type="button">สั่งปริ้น</button></span></div>';const x=f();Object.entries(by).forEach(([store,items])=>{const pg=document.createElement('section');pg.className='page';pg.innerHTML=`<div class="head"><div><b>ใบส่งสินค้า</b><div class="shop">ร้าน: ${esc(store)}</div></div><div>วันที่: ${esc((x.end||x.start).split('-').reverse().join('/'))}<br>PS: ${esc(x.ps||'ทั้งหมด')}</div></div><table><thead><tr><th>#</th><th>รหัส</th><th>รายการ</th><th>จำนวน</th><th>ราคา/หน่วย</th><th>รวม</th></tr></thead><tbody></tbody></table><div class="sign"><div>ผู้จัดของ</div><div>ผู้ส่ง</div><div>ผู้รับสินค้า</div></div>`;const tb=pg.querySelector('tbody');items.forEach((l,i)=>{const tr=document.createElement('tr');tr.innerHTML=`<td>${i+1}</td><td>${esc(l.code)}</td><td>${esc(l.name)}<br><small>${esc(l.brand)} · ${esc(l.size)} · ${esc(l.type)}</small></td><td class="r">${F(l.qty)}</td><td class="r"></td><td class="r total">0.00</td>`;const inp=document.createElement('input');inp.className='price';inp.type='number';inp.step='0.01';inp.value=String(Math.round(N(l.unit)*100)/100);inp.dataset.qty=l.qty;tr.children[4].appendChild(inp);tb.appendChild(tr)});tb.insertAdjacentHTML('beforeend','<tr><td colspan="5" class="r"><b>รวม</b></td><td class="r billTotal">0.00</td></tr>');ov.appendChild(pg)});document.body.appendChild(ov);document.body.classList.add('printMode');ov.querySelectorAll('.price').forEach(i=>i.oninput=()=>recalc(ov));$('#doitClosePrint').onclick=closePrint;$('#doitPrintNow').onclick=e=>{e.preventDefault();e.stopPropagation();printNow()};$('#doitConfirmPrint').onclick=()=>closeStore(true);$('#storeSelect')?.addEventListener('change',updateConfirmBtn);updateConfirmBtn();recalc(ov)}
function refresh(){closePrint();window.DOIT_JSON_APP?.rerender?.()||document.dispatchEvent(new CustomEvent('doit:stateChanged'))}
function closeStore(save){const x=f();if(!x.receiver){alert('กรุณาเลือกร้านจริงก่อนปิดบิลหรือล้างร้าน');return}const st=state(),head=scopeHead()+x.receiver+'|',removed=[];['send','add','pull'].forEach(k=>{const obj=st[k]||{};Object.keys(obj).forEach(key=>{if(key.startsWith(head)){removed.push({map:k,key,qty:N(obj[key])});delete obj[key]}});st[k]=obj});if(!removed.length){alert('ร้านนี้ไม่มีรายการค้างในช่วงวันที่/PS นี้');return}if(save){const h=hist();h.unshift({at:new Date().toISOString(),store:x.receiver,start:x.start,end:x.end,ps:x.ps,items:deliveryLines().filter(v=>v.store===x.receiver)});saveHist(h.slice(0,200))}saveState(st);alert(save?'ปิดบิลและเก็บเข้า History แล้ว':'ล้างรายการของร้านนี้แล้ว');refresh()}
function bind(){document.addEventListener('click',e=>{const id=e.target?.id;if(id==='prepPrint'){buildPrint(e)}else if(id==='doitConfirmPrint'||id==='closeBillBtn'||id==='clearStoreBtn'){e.preventDefault();e.stopImmediatePropagation();closeStore(id!=='clearStoreBtn')}else if(id==='exportCsv'){csv(e)}},true)}
function patch(){if(!window.DOIT_JSON_APP||window.DOIT_JSON_APP.__printFix308)return false;const app=window.DOIT_JSON_APP,old=app.load.bind(app);app.load=(p,m={})=>{payload=p;meta=m||{};const all=(p.rows||p||[]).map(r=>({date:T(r.date),inv:T(r.inv),store:T(r.store),tele:T(r.tele),isTele:!!r.isTele,ps:T(r.ps),code:T(r.code),sku:T(r.sku),brand:T(r.brand),size:T(r.size),type:T(r.type)||'INVC',qty:N(r.qty),unit:N(r.unit),amt:N(r.amt)}));rows=all;old(Array.isArray(p)?all.filter(r=>!realTele(r)):{...p,rows:all.filter(r=>!realTele(r))},m);setTimeout(()=>window.DOIT_TELESALE_DRAWER?.loadRows(all,{start:T($('#startDate')?.value),end:T($('#endDate')?.value),ps:T($('#psSelect')?.value)}),100)};app.__printFix308=true;return true}
function boot(){bind();if(!patch())setTimeout(boot,300)}if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',boot);else boot();
})();